var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"……응. 네가 없는 동안 집에 몇 번 찾아왔어. 클림트 씨.","JPN":"……うん。レアがいない間、何度か家に来てたよ。クリムトさん。","ENG":"...Yes. While you were away, Mr. Klimt came by our place several times.","TWN":"……嗯，你不在的時候，克里姆有來家裡找過我幾次。"},"stage":{"bg":"WINTER_STREET","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"몇 번 찾아오다니……. 왜 그동안 말 안 한 거야?","JPN":"何度かって……なんで今まで黙ってたの？","ENG":"Several times? Why didn’t you ever tell me?","TWN":"他找過你幾次……那你怎麼都沒跟我說？"},"stage":{"bg":"WINTER_STREET","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"공연에 참가하라는 제안 때문이었거든.","JPN":"公演に参加してくれっていう内容だったから。","ENG":"He wanted me to be a part of the performance.","TWN":"他來是想要我一起參與演出，"},"stage":{"bg":"WINTER_STREET","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_LAUGH"}}}},{"id":"L7_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"무대에 서 본 적은 위문 공연이나 채권 판촉 때문에 몇 번 정도라, 거절했지만.","JPN":"舞台は慰問公演とか、債権の販促で何度か立った程度だから断ったけど。","ENG":"I’ve performed on stage only a couple of times for bond promotions and morale-boosting concerts, so I turned him down.","TWN":"但我只有幾次在勞軍或是推銷債券時表演過的經驗，所以就拒絕他了。"},"stage":{"bg":"WINTER_STREET","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"다른 얘기는 안 했어?","JPN":"他には何も言わなかった？","ENG":"You guys didn’t talk about anything else?","TWN":"他沒說其他的？"},"stage":{"bg":"WINTER_STREET","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"으음, 글쎄. 아주머니께 음악에 대해 물어 보기도 했는데…….","JPN":"う～ん、そうね。おばさんに音楽について聞いてみたりはしてたけど……","ENG":"Hmm, well. He did talk to Madam a little bit about music...","TWN":"嗯，這個嘛，他是有跟伯母聊一些音樂的事……"},"stage":{"bg":"WINTER_STREET","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_SURPRISE"}}}},{"id":"L10_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"뭐……?","JPN":"は……？","ENG":"What...?","TWN":"什麼……？"},"stage":{"bg":"WINTER_STREET","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_SURPRISE"}}}},{"id":"L11_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"그걸 내버려 뒀어? 너 우리 엄마가……!","JPN":"それを黙って見てたの？　私のお母さんが……！","ENG":"And you just let it happen? You know talking about that kind of stuff...!","TWN":"你就這樣放任他？你明知道我媽她……！"},"stage":{"bg":"WINTER_STREET","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_SURPRISE"}}}},{"id":"L12_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"수, 숨겨서 미안해. 레아. 나쁜 뜻이 있어서 그런 건 아니야.","JPN":"だ、黙っててごめんね、レア。悪気があってそうしたわけじゃないの。","ENG":"S-Sorry for not telling you, Leah. I know it sounds bad, but it’s not like that.","TWN":"對不起，蕾亞，我不是故意要瞞著你的。"},"stage":{"bg":"WINTER_STREET","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_DESPAIR"}}}},{"id":"L13_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"너도 출장 다녀온 뒤로 바빴던 데다가, 아주머니도 다른 사람과 대화하는 게 즐거우셨던 것 같아서…….","JPN":"レアは出張帰りで忙しかったし、おばさんも他の人と話すのが楽しそうだったから……","ENG":"You’ve been so busy with your business trip and all, and well, she seemed so happy talking to other people so...","TWN":"你出差回來後就一直很忙，而且我看伯母也滿喜歡跟人聊天的……"},"stage":{"bg":"WINTER_STREET","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"WINTER_STREET","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"미안해, 안젤라. 엄마 병수발은 다 떠맡겨 놓고 화내서.","JPN":"ごめん、アンジェラ。お母さんの世話を任せっぱなしなのに怒っちゃって。","ENG":"I’m sorry, Angela. I just let you care for Mom and got angry with you.","TWN":"安潔拉.，對不起，我把照顧媽媽的事都推給你，竟然還對你發脾氣。"},"stage":{"bg":"WINTER_STREET","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"괜찮아. 그만큼 너한테는 아주머니가 소중하다는 거잖아.","JPN":"いいのよ。それくらいレアにとっておばさんは大事ってことだから。","ENG":"It’s okay. I know how important Madam is to you.","TWN":"沒關係，我知道你很在意媽媽。"},"stage":{"bg":"WINTER_STREET","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_LAUGH"}}}},{"id":"L17_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"그런데……. 그 사람은 왜?","JPN":"でも……その人がどうかした？","ENG":"But... What’s with Mr. Klimt?","TWN":"不過……你怎麼會問起他的事？"},"stage":{"bg":"WINTER_STREET","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"예전 직장에서 부탁을 받았어. 클림트와 관련된 일이야.","JPN":"昔の職場から頼まれてさ。クリムトと関係があるんだ。","ENG":"I got a request from my old workplace. It’s related to Mr. Klimt.","TWN":"以前的同事拜託我打聽有關克里姆的事。"},"stage":{"bg":"WINTER_STREET","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"혹시 그 사람에 대해 뭔가 들은 거 없어? 어디 자주 간다거나, 취미라거나.","JPN":"あの人について何か聞いたことはない？　よく出かける場所とか、趣味とか。","ENG":"Did you by any chance hear anything about him while you were there? Such as what kind of places he went to or hobbies he had?","TWN":"你知道什麼有關於他的事嗎？譬如說他常去的地方，或是興趣之類的？"},"stage":{"bg":"WINTER_STREET","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"글쎄……. 생각해 보면 개인적인 얘기는 거의 못 들은 것 같은데…….","JPN":"さあ……考えてみたら個人的な話はあまり聞いてないような……","ENG":"Well... Now that I think about it, I never really heard anything about his personal life...","TWN":"我也不太清楚……現在想想，他好像很少談到自己的事……"},"stage":{"bg":"WINTER_STREET","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_DESPAIR"}}}},{"id":"L21_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"아, 맞다. 자기는 원래 수도에서 태어났다고 말한 적이 있어.","JPN":"あ、そうだ。自分が元々首都の生まれだって言ってたわ。","ENG":"Ah, right. I did hear he was born in Tanaberin.","TWN":"我想到了，他有提到他是在首都出生的。"},"stage":{"bg":"WINTER_STREET","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"예전에 살던 동네에 가 봤더니 침식지대가 되어 있었다고 아쉬워했거든.","JPN":"昔住んでた街に行ってみたら、侵食地帯になってたって残念そうにしてた。","ENG":"And that when he went to see the old neighborhood he grew up in, he was devastated to see it had turned into a Corrupted Area.","TWN":"還說他回去以前住過的地方，結果發現那裡變成侵蝕地帶，覺得不勝唏噓。"},"stage":{"bg":"WINTER_STREET","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_IDLE"}}}}]`);export{e as default};